INSERT INTO CHANGE_AUTH_LOG (
    CHANGE_AUTH_LOG_ID, USER_ID, CHANGE_AUTH_TIME
)
VALUES (
    CHANGE_AUTH_LOG_ID_SEQ.NEXTVAL, #{userOid}, #{changeAuthTime}
)

