UPDATE
	${schema}.lgn_log
SET
	lgt_dt = #{lgtDt},
	ssn_contn_hr = TIMESTAMPDIFF(SECOND, lgn_dt, #{lgtDt})
WHERE
	user_id = #{dto.userId}
	AND user_oid = #{dto.userOid}
	AND ssn_id = #{dto.loginSsnId}
	AND lgt_dt IS NULL
